1	const countNeighbors = (cell: [number, number], cells: [number, number][]): number => {
2	  const [x, y] = cell;
3	  let neighborCount = 0;
4	  for (const [cx, cy] of cells) {
5	    if (cx === x && cy === y) continue;
6	    if (Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1) neighborCount++;
7	  }
8	  return neighborCount;
9	};
10	
11	export function nextGeneration(cells: [number, number][]): [number, number][] {
12	  return cells.filter(cell => {
13	    const neighborCount = countNeighbors(cell, cells);
14	    return neighborCount === 2 || neighborCount === 3;
15	  });
16	}
